internal static string FromPascalCase(string input)
{
    var matches = PascalCaseWordPartsRegex().Matches(input);
    if (matches.Count == 0)
    {
        return input;
    }

    // Pre-calculate total length to size the builder once
    int totalLength = matches.Count - 1; // spaces between words
    for (int i = 0; i < matches.Count; i++)
    {
        totalLength += matches[i].Value.Length;
    }

    var sb = new System.Text.StringBuilder(totalLength);
    bool allUpperOrSpace = true;

    for (int i = 0; i < matches.Count; i++)
    {
        if (i > 0)
        {
            sb.Append(' ');
        }

        var match = matches[i];
        var value = match.Value;

        bool isAllUpper = IsAllUpperCase(value);
        bool keepUpper = isAllUpper &&
            (value.Length > 1 || (match.Index > 0 && input[match.Index - 1] == ' ') || value == "I");

        if (keepUpper)
        {
            sb.Append(value);
        }
        else
        {
            allUpperOrSpace = false;
            AppendLowerInvariant(sb, value);
        }

        if (!isAllUpper)
        {
            allUpperOrSpace = false;
        }
    }

    if (allUpperOrSpace && matches.Count > 1)
    {
        // All words were uppercase acronyms — lowercase the whole result
        var result = sb.ToString().ToLowerInvariant();
        return Concat(char.ToUpperInvariant(result[0]), result.AsSpan(1));
    }

    if (sb.Length > 0)
    {
        sb[0] = char.ToUpperInvariant(sb[0]);
    }

    return sb.ToString();
}

private static bool IsAllUpperCase(string value)
{
    for (int i = 0; i < value.Length; i++)
    {
        if (!char.IsUpper(value[i]))
        {
            return false;
        }
    }
    return true;
}

