public static string Dehumanize(this string input)
{
    var words = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    if (words.Length == 0)
    {
        return input;
    }

    if (words.Length == 1)
    {
        return CapitalizeWord(words[0]);
    }

    var sb = new System.Text.StringBuilder(input.Length);
    foreach (var word in words)
    {
        sb.Append(CapitalizeWord(word));
    }
    return sb.ToString();
}

/// <summary>
/// Capitalizes the first character of a word.
/// </summary>
private static string CapitalizeWord(string word)
{
    if (string.IsNullOrEmpty(word))
    {
        return word;
    }
    if (char.IsUpper(word[0]))
    {
        return word;
    }
    return StringReadabilityExtensions.Concat(char.ToUpperInvariant(word[0]), word.AsSpan(1));
}

