    var words = humanized.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    if (words.Length == 0)
    {
        return humanized;
    }

    var sb = new System.Text.StringBuilder(humanized.Length);
    foreach (var word in words)
    {
        sb.Append(CapitalizeWord(word));
    }
    return sb.ToString();
}

